import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"21. Period Of Employment","description":"","frontmatter":{"title":"21. Period Of Employment","eba":"Doctors in Training 2022-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/21-period-of-employment.md","filePath":"ebas/doctors-in-training/doctor-employment/21-period-of-employment.md"}'),n={name:"ebas/doctors-in-training/doctor-employment/21-period-of-employment.md"};function i(s,e,l,c,p,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_21-period-of-employment" tabindex="-1">21. Period Of Employment <a class="header-anchor" href="#_21-period-of-employment" aria-label="Permalink to &quot;21. Period Of Employment&quot;">​</a></h1><p>This clause does not apply to casual employees.</p><p><strong>21.1</strong> Minimum period of employment</p><p><strong>(a)</strong> A Doctor’s period of employment may be not less than 52 weeks, unless otherwise specifically stated.</p><p><strong>(b)</strong> To improve secure employment for Doctors, Health Services will implement employment contracts of two-years or longer duration to the extent possible.</p><p><strong>21.2</strong> Minimum period of employment – exception</p><p>The restrictions in the above subclause 21.1(a) do not apply to:</p><p><strong>(a)</strong> Medical Officers, Senior Medical Officers or Casual Doctors as defined in subclauses 3.1(w), 3.1(ff) and 19.1 of this Agreement; or</p><p><strong>(b)</strong> facilitate placements arranged by a Specialist Medical College or at the request of the Doctor to meet Specialist Medical College training requirements; or</p><p><strong>(c)</strong> to replace an absence for a specific period of less than the minimum period of employment that is known before the period of employment commences</p><p><strong>21.3</strong> Effect of Certain Absences on Period of Employment</p><p><strong>(a)</strong> Where a Doctor is engaged for a period under this clause and is absent for a continuous period exceeding three months from employment as a result of Parental Leave (see <a href="/eba/ebas/doctors-in-training/leave/67-parental-leave.html">clause 67</a>), Family Violence Leave (see <a href="/eba/ebas/doctors-in-training/leave/71-family-violence-leave.html">clause 71</a>) or Carer’s Leave (see <a href="/eba/ebas/doctors-in-training/leave/61-personal-sick-carer-s-leave.html">clause 61</a>), the provisions of subclauses 21.3(b)(i) and (b)(ii) shall apply.</p><p><strong>(b)</strong> Extension of contract – Parental Leave, Carer’s Leave and Family Violence</p><p><strong>(i)</strong> Prior to the scheduled commencement of a period of Parental Leave exceeding three months, the Health Service shall offer to vary the period of the contract to accommodate the length of the Parental Leave and the length of the remaining period of the existing contract. Where a Doctor exercises the right to request additional Parental Leave either under subclause 67.12 and the Health Service agrees, or further period of Parental Leave under <a href="/eba/ebas/doctors-in-training/leave/67-parental-leave.html">clause 67</a> (in the event of additional pregnancy), the Health Service shall offer to further vary the period of the contract to accommodate for the length of the further period of Parental Leave.</p><p>Example A Doctor commenced in February and has a contract that ends in February the following year. The Doctor commences 12 months parental leave in September. Prior to commencing parental leave the Health Service shall offer the Doctor a variation to their contract. The variation provides for the Doctor to extend their employment for the period of 12 months parental leave and to return to work at the cessation of the parental leave and complete the remaining 5 months of their initial contract term representing the period between September and February that had not been completed prior to the absence on parental leave.</p><p><strong>(ii)</strong> A Health Service shall also offer to vary the period of a Doctor’s contract to accommodate an absence exceeding three months due to Carer’s Leave or Family Violence Leave and the length of the remaining period of the existing contract. In the case of such an absence due to Carer’s Leave or Family Violence, the obligation to offer to extend the contract will arise upon receipt of a request to be absent for a period exceeding three months.</p><p><strong>(iii)</strong> Nothing prevents a Doctor requesting, and a Health Service agreeing to, a period other than the remaining period of the contract.</p><p>Example A Doctor commenced in February and has a contract that ends in February the following year. The Doctor commences 12 months parental leave in April. Prior to commencing parental leave the Health Service shall offer the Doctor a variation to their contract. The Doctor indicated they intend on obtaining employment next February and sought not to have their contract extended as they intended on obtaining employment in the following February. The Health Service agreed to the Doctor’s request and the contract was not extended beyond the original date the contract expires.</p><p>Plain language terms: contract term.</p>',19)])])}const f=t(n,[["render",i]]);export{d as __pageData,f as default};
